// IGMP Messages
CONSTANT IGMP_MEMBERSHIP_QUERY = 0x11
CONSTANT IGMP_V1_MEMBERSHIP_REPORT = 0x12
CONSTANT IGMP_V2_MEMBERSHIP_REPORT = 0x16
CONSTANT IGMP_LEAVE_GROUP = 0x17

// Router sends periodic queries
FUNCTION router_send_query(interface)
 query = {
 type: IGMP_MEMBERSHIP_QUERY,
 max_response_time: 100, // 10 seconds
 group_address: 0, // general query
 checksum: calculate_checksum(query)
 }
 send_udp(interface, ALL_HOSTS_GROUP, query)
END FUNCTION

// Host sends membership report
FUNCTION host_send_report(group_address)
 report = {
 type: IGMP_V2_MEMBERSHIP_REPORT,
 group_address: group_address,
 checksum: calculate_checksum(report)
 }
 send_udp(ALL_ROUTERS_GROUP, report)
END FUNCTION

// Host leaves group
FUNCTION host_send_leave(group_address)
 leave = {
 type: IGMP_LEAVE_GROUP,
 group_address: group_address,
 checksum: calculate_checksum(leave)
 }
 send_udp(ALL_ROUTERS_GROUP, leave)
END FUNCTION

// Router processes membership reports
FUNCTION router_process_report(received_group, interface)
 // Add interface to group membership list
 group_membership[received_group].add(interface)
 // Set timer for this group membership
 timer[received_group] = GROUP_MEMBERSHIP_TIMEOUT
END FUNCTION
